svg.script:
	/*
	* This function returns the innermost SVG object that triggered the event
	* and that has a non-null id attribute. This can be either the event's
	* target itself, or its parent node, or the first ancestor of the target
	* with a non-null id.
	*
	* Input Parameters:
	*   event - The JavaScript object describing the triggering event
	* Return Value:
	*   The target node or first target's ancestor with a non-null id.
	*/
	function get_target (event)
	{
		var target = event.getTarget();
		while (target && !target.getAttribute('id'))
			target = target.getParentNode();
		return target;
	}

	/*
	* This function places the highlighting box around the indicated object and
	* makes it visible or invisible.
	*
	* Input Parameters:
	*   target     - SVG element where the box should be positioned on.
	*   visibility - the setting for the box's visibility property.
	*/
	function move_box (target, visibility)
	{
		var box_name = 'hilite_box';
		var svgdoc = target.getOwnerDocument();
		var svgobj = svgdoc.getElementById (box_name);
		if (svgobj)
		{
			svgobj.setAttribute ('x', target.getAttribute('x'));
			svgobj.setAttribute ('y', target.getAttribute('y'));
			var svgstyle = svgobj.getStyle();
			if (svgstyle)
				svgstyle.setProperty ('visibility', visibility);
		}
	}

	/*
	* This function makes the highlighting box visible or invisible around
	* an icon depending on whether the mouse was moved over or out-of the icon.
	*
	* Input Parameters:
	*   event - The JavaScript object describing the triggering event
	*/
	function hilite_btn (event)
	{
		var target = get_target(event);
		switch (event.getType()+'')
		{
			case 'mouseover':
				move_box (target, 'visible');
				break;
			case 'mouseout':
				move_box (target, 'hidden');
				break;
		}
	}

	/*
	* This function creates a duplicate of the object that was clicked and
	* adds it to the "contents" group:
	* The object's node is the event.target.
	* The node is cloned.
	* The cloned node's x & y attributes and its fill property or set to
	* random values.
	* The cloned node is appended to the contents group.
	* 
	* Input Parameters:
	*   event - The JavaScript object describing the triggering event
	*/
	function clone_me (event)
	{
		// List of colors assigned randomly to the clone object.
		var colors = new Array
			('red', 'blue', 'yellow', 'cyan', 'green', 'gray', 'white', 'brown');

		// Retrieve node of object that was clicked on.
		var target = get_target(event);

		var svgdoc = target.getOwnerDocument();

		// Show highlight box around the icon that was clicked on.
		// (This should already be done because of the mouseover event, but the
		// display might not be updated by the time this event is triggered. This
		// call makes sure the display gets updated.)
		move_box (target, 'visible');

		// Determine random values for the new elements x, y, and fill attributes
		// and properties.
		var x = 10+335*Math.random();
		var y = 10+200*Math.random();
		var fill = Math.floor(colors.length*Math.random());
		if (fill == colors.length) fill = colors.length-1;
		fill = colors[fill];

		// Clone the object and set its attributes and properties.
		var newnode = target.cloneNode(false);
		newnode.setAttribute ('x', x);
		newnode.setAttribute ('y', y);
		newnode.getStyle().setProperty ('fill', fill);

		// Retrieve the node for "contents" group.
		var contents = svgdoc.getElementById ('contents');

		// Insert the cloned object into the contents group node.
		newnode = contents.appendChild (newnode);
	}

	/*
	* This function moves the object that was clicked to the back of all other 
	* objects in its group:
	* The object's node is the event.target.
	* The node is removed from its parent node (its container group).
	* The node is reinserted into its parent node before the first child node
	* in the parent.
	* 
	* Input Parameters:
	*   event - The JavaScript object describing the triggering event
	*/
	function arrange_me (event)
	{
		// Retrieve node of object that was clicked on.
		var target = get_target(event);

		// Retrieve node of object's parent group.
		var groupnode = target.getParentNode();

		// Remove object's node from its group node.
		groupnode.removeChild (target);

		// Insert object's node into its group node before the first child of the
		// group.
		groupnode.insertBefore (target, groupnode.getFirstChild());
	}
